        }
    }
    if (index == -1) {
        return lengthCDF - 1;
    }
    return index;
}

int findIndexBin(double * CDF, int beginIndex, int endIndex, double value) {
    if (beginIndex > endIndex)
        return -1;
    int middleIndex = beginIndex + ((endIndex - beginIndex) / 2);

    if (value <= CDF[middleIndex]) {
        if (0 == middleIndex)
            return middleIndex;
        else if (value > CDF[middleIndex - 1])
            return middleIndex;
        else if (value == CDF[middleIndex - 1]) {
            while (0 < middleIndex && CDF[middleIndex - 1] == value)
                middleIndex--;
            return middleIndex;
        }
    }
    if (value < CDF[middleIndex])
        return findIndexBin(CDF, beginIndex, middleIndex + 1, value);
    return findIndexBin(CDF, middleIndex - 1, endIndex, value);
}

